const page = await $page;
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

const rawUrl = $json["E-commerce Url"].trim().replace(/\/$/, '');
const origin = rawUrl.match(/^(https?:\/\/[^\/]+)/)[1];
const email = $json["user name"];
const password = $json["password"];

const loginUrl = `${origin}/login`;

const DASHBOARD_CANDIDATES = [
  '/admin',
  '/dashboard',
  '/admin/dashboard',
  '/panel',
  '/control-panel',
  '/manage',
  '/management',
  '/back-office',
  '/backoffice',
  '/portal',
  '/home',
  '/overview',
];

console.log('Login URL:', loginUrl);

// Go to login page
await page.goto(loginUrl, { waitUntil: 'networkidle2' });
await sleep(1000);

// Clear fields and fill credentials
await page.$eval('input[type="email"]', el => el.value = '');
await page.type('input[type="email"]', email);
await page.$eval('input[type="password"]', el => el.value = '');
await page.type('input[type="password"]', password);
await sleep(500);

// Strategy 1: click submit button inside the form
const clicked = await page.evaluate(() => {
  const form = document.querySelector('form');
  if (!form) return false;
  const btn = form.querySelector('button[type="submit"], input[type="submit"], button');
  if (btn) { btn.click(); return true; }
  return false;
});

console.log('Strategy 1 (form button) clicked:', clicked);

// Strategy 2: press Enter as fallback
if (!clicked) {
  console.log('Falling back to Enter key...');
  await page.focus('input[type="password"]');
  await page.keyboard.press('Enter');
}

// Wait for URL to leave /login
await page.waitForFunction(
  () => !window.location.href.includes('/login'),
  { timeout: 15000 }
).catch(() => console.log('⚠️ Still on login page after 15s'));

const postLoginUrl = page.url();
console.log('URL after login:', postLoginUrl);

if (postLoginUrl.includes('/login')) {
  const formHtml = await page.evaluate(() => {
    const form = document.querySelector('form');
    return form ? form.innerHTML : document.body.innerHTML.slice(0, 2000);
  });
  console.log('Form HTML:', formHtml);
  throw new Error('Login failed — check console for form HTML.');
}

// Auto-detect the correct dashboard URL
let detectedDashboardUrl = null;

// First check: did login already land us on a known dashboard endpoint?
const autoLandedPath = page.url().replace(origin, '');
const autoMatched = DASHBOARD_CANDIDATES.find(path => autoLandedPath.startsWith(path));
if (autoMatched) {
  detectedDashboardUrl = page.url();
  console.log('✅ Auto-landed on dashboard:', detectedDashboardUrl);
}

// Second check: try each candidate until one works
if (!detectedDashboardUrl) {
  for (const candidate of DASHBOARD_CANDIDATES) {
    const tryUrl = `${origin}${candidate}`;
    console.log('Trying:', tryUrl);

    await page.goto(tryUrl, { waitUntil: 'networkidle2' });
    await sleep(1000);

    const landed = page.url();
    const isLoginPage = landed.includes('/login');
    const isHomePage = landed === `${origin}/` || landed === origin;
    const hasContent = await page.evaluate(() => document.body.innerText.trim().length > 100);

    if (!isLoginPage && !isHomePage && hasContent) {
      detectedDashboardUrl = landed;
      console.log('✅ Dashboard found at:', detectedDashboardUrl);
      break;
    }

    console.log(`✗ ${candidate} didn't work (landed: ${landed})`);
  }
}

if (!detectedDashboardUrl) {
  throw new Error('Could not detect dashboard URL — tried all common endpoints.');
}

// ✅ Wait for meaningful content to appear before extracting
await page.waitForFunction(
  () => document.body.innerText.trim().length > 200,
  { timeout: 10000 }
).catch(() => console.log('⚠️ Page content slow to load'));

await sleep(1500);

console.log('Final URL:', page.url());

// Extract full page content
const data = await page.evaluate(() => {

  const getLeafText = () =>
    Array.from(document.querySelectorAll('body *'))
      .filter(el => el.children.length === 0 && el.innerText?.trim().length > 0)
      .map(el => el.innerText.trim())
      .filter((v, i, arr) => arr.indexOf(v) === i);

  const getFullHtml = () => document.body.innerHTML;

  const getNativeTables = () =>
    Array.from(document.querySelectorAll('table')).map(table => ({
      type: 'native-table',
      headers: Array.from(table.querySelectorAll('th')).map(th => th.innerText.trim()).filter(Boolean),
      rows: Array.from(table.querySelectorAll('tr'))
        .map(row => Array.from(row.querySelectorAll('td, th')).map(cell => cell.innerText.trim()))
        .filter(row => row.some(cell => cell.length > 0))
    }));

  const getDivTables = () => {
    const tableContainers = Array.from(document.querySelectorAll(
      '[role="table"], [role="grid"], [role="treegrid"]'
    ));
    return tableContainers.map(container => ({
      type: 'div-table',
      headers: Array.from(container.querySelectorAll('[role="columnheader"]'))
        .map(h => h.innerText.trim()).filter(Boolean),
      rows: Array.from(container.querySelectorAll('[role="row"]'))
        .map(row =>
          Array.from(row.querySelectorAll('[role="cell"], [role="gridcell"], [role="columnheader"]'))
            .map(cell => cell.innerText.trim())
        ).filter(row => row.some(cell => cell.length > 0))
    }));
  };

  const getListTables = () => {
    const candidates = Array.from(document.querySelectorAll(
      'ul, ol, [class*="list"], [class*="grid"], [class*="table"], [class*="row"]'
    )).filter(el => {
      const children = Array.from(el.children);
      return children.length >= 3 &&
        children.slice(0, 3).every(c => c.tagName === children[0].tagName);
    });
    return candidates.map(container => ({
      type: 'list-table',
      rows: Array.from(container.children)
        .map(row => row.innerText.trim())
        .filter(Boolean)
    }));
  };

  const getTables = () => {
    const native = getNativeTables();
    const divs = getDivTables();
    const lists = getListTables();
    return [...native, ...divs, ...lists];
  };

  const getLinks = () =>
    Array.from(document.querySelectorAll('a[href]')).map(a => ({
      text: a.innerText.trim(),
      href: a.href
    })).filter(l => l.text.length > 0);

  const getImages = () =>
    Array.from(document.querySelectorAll('img')).map(img => ({
      src: img.src,
      alt: img.alt
    }));

  const getMeta = () => ({
    title: document.title,
    description: document.querySelector('meta[name="description"]')?.content || '',
    ogTitle: document.querySelector('meta[property="og:title"]')?.content || '',
    ogDescription: document.querySelector('meta[property="og:description"]')?.content || '',
  });

  const getNumbers = () =>
    Array.from(document.querySelectorAll('body *'))
      .filter(el => el.children.length === 0)
      .map(el => el.innerText?.trim())
      .filter(text => text && /\d/.test(text))
      .filter((v, i, arr) => arr.indexOf(v) === i);

  const getHeadings = () =>
    Array.from(document.querySelectorAll('h1, h2, h3, h4, h5, h6'))
      .map(h => ({ tag: h.tagName, text: h.innerText.trim() }));

  const getCharts = () =>
    window.chartData || window.__data__ || window.__NEXT_DATA__ || null;

  return {
    meta: getMeta(),
    headings: getHeadings(),
    text: getLeafText(),
    numbers: getNumbers(),
    tables: getTables(),
    links: getLinks(),
    images: getImages(),
    charts: getCharts(),
    html: getFullHtml(),
    url: window.location.href
  };
});

return [{ json: data }];

