const html = $input.first().json.html || '';

/**
 * CLEAN HTML
 */
let cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<img[^>]*>/gi, '')
  .replace(/<iframe[\s\S]*?<\/iframe>/gi, '');

/**
 * STRIP TAGS
 */
function stripTags(str) {
  return str.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
}

/**
 * =========================
 * NEW: FULL TEXT EXTRACTION
 * =========================
 */
function extractFullText(html) {
  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>|<\/div>|<\/h[1-6]>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\n+/g, '\n')
    .replace(/\s+/g, ' ')
    .replace(/\n\s+/g, '\n')
    .trim();
}

/**
 * =========================
 * NEW: FIND TABLE TITLES
 * =========================
 */
function extractTablesWithTitles(html) {
  const tables = html.match(/<table[\s\S]*?<\/table>/gi) || [];
  const results = [];

  for (const table of tables) {
    const index = html.indexOf(table);
    const before = html.substring(Math.max(0, index - 500), index);

    // try caption first
    let titleMatch = table.match(/<caption[^>]*>([\s\S]*?)<\/caption>/i);

    // fallback: last heading before table
    if (!titleMatch) {
      titleMatch = before.match(/<(h1|h2|h3|h4|h5|h6)[^>]*>([\s\S]*?)<\/\1>(?![\s\S]*<\1)/i);
    }

    const title = titleMatch
      ? stripTags(titleMatch[1] || titleMatch[2])
      : '';

    results.push({
      title,
      html: table
    });
  }

  return results;
}

/**
 * =========================
 * 1. TABLE PARSER (UPDATED)
 * =========================
 */
function parseTables(html) {
  const tables = extractTablesWithTitles(html);
  const rows = [];

  for (const tableObj of tables) {
    const trs = tableObj.html.match(/<tr[\s\S]*?<\/tr>/gi) || [];

    // add title as separator
    if (tableObj.title) {
      rows.push([`### ${tableObj.title}`]);
    }

    for (const tr of trs) {
      const cells = [];
      const tds = tr.match(/<(td|th)[\s\S]*?<\/(td|th)>/gi) || [];

      for (const td of tds) {
        const text = stripTags(td);
        if (text) cells.push(text);
      }

      if (cells.length >= 2) {
        rows.push(cells);
      }
    }
  }

  return rows;
}

/**
 * =========================
 * 2. UNIVERSAL TEXT PARSER
 * =========================
 */
function parseByContent(html) {
  const rawTexts = html.match(/>([^<>]+)</g) || [];

  const texts = rawTexts
    .map(t => t.replace(/[><]/g, '').trim())
    .filter(t =>
      t &&
      t.length > 1 &&
      t.length < 100 &&
      !t.includes('✦') &&
      !t.includes('Shop') &&
      !t.includes('Admin Dashboard')
    );

  const rows = [];

  for (let i = 0; i < texts.length; i++) {
    const t = texts[i];

    if (/^\$\d+/.test(t)) {
      const name = texts[i - 3] || '';
      const desc = texts[i - 2] || '';
      const category = texts[i - 1] || '';
      const price = t;
      const stock = texts[i + 1] || '';

      const row = [
        (name + ' ' + desc).trim(),
        category,
        price,
        stock
      ].filter(x => x);

      if (row.length >= 3) {
        rows.push(row);
      }
    }
  }

  return rows;
}

/**
 * =========================
 * RUN BOTH METHODS
 * =========================
 */
let structuredRows = parseTables(cleaned);

if (structuredRows.length === 0) {
  structuredRows = parseByContent(cleaned);
}

/**
 * =========================
 * REMOVE "ACTION" COLUMN
 * =========================
 */
structuredRows = structuredRows.map(row =>
  row.filter(cell =>
    !/delete|edit|update|action|add/i.test(cell)
  )
);

/**
 * =========================
 * FORMAT STRUCTURED TEXT
 * =========================
 */
const structuredLines = structuredRows.map(row => row.join(' | '));
const structuredText = [...new Set(structuredLines)].join('\n');

/**
 * =========================
 * NEW: FULL TEXT OUTPUT
 * =========================
 */
const fullText = extractFullText(cleaned)
  .split('\n')
  .map(line => line.trim())
  .filter(line =>
    line &&
    !/delete|edit|update|action|add/i.test(line)
  )
  .join('\n');

/**
 * =========================
 * SAFETY OUTPUT
 * =========================
 */
if (!structuredText && !fullText) {
  return [{
    json: {
      success: false,
      message: "No usable data extracted"
    }
  }];
}

/**
 * =========================
 * FINAL OUTPUT
 * =========================
 */
return [{
  json: {
    success: true,
    text: structuredText,   // tables (your original logic)
    full_text: fullText     // NEW: full page text
  }
}];

