const data = $input.first().json;

let raw = data;

// 🔥 Step 1: Try common paths
if (raw.output) raw = raw.output;
if (raw.result) raw = raw.result;

// 🔥 Step 2: Parse until it's not a string anymore
try {
  while (typeof raw === "string") {
    raw = JSON.parse(raw);
  }
} catch (e) {
  return [{ json: { text: "", valid: false, error: "Invalid JSON parsing" } }];
}

// 🔥 Step 3: Final check
if (!Array.isArray(raw)) {
  return [{
    json: {
      text: "",
      valid: false,
      error: "Not an array"
    }
  }];
}

// 🔥 Step 4: Build TEXT output
let lines = [];
let isGlobalValid = true;

raw.forEach((product, index) => {

  const isValid =
    product.product_name &&
    product.category &&
    product.price &&
    product.stock &&
    Array.isArray(product.issues) &&
    Array.isArray(product.recommendations) &&
    (product.issues.length === 0 || product.recommendations.length > 0);

  if (!isValid) {
    isGlobalValid = false;
  }

  // 🔥 Format issues & recommendations as inline text
  const issuesText = product.issues
    .map((issue, i) => `${i}: ${issue}`)
    .join(" | ");

  const recText = product.recommendations
    .map((rec, i) => `${i}: ${rec}`)
    .join(" | ");

  // 🔥 Build ONE LINE per product
  const line = `${product.product_name} , ${product.category} , ${product.price} , ${product.stock} , ${issuesText} , ${recText}`;

  lines.push(line);
});

// 🔥 Join all lines with \n
const finalText = lines.join("\n");

// ✅ Return EXACT format you want
return [{
  json: {
    text: finalText,
    valid: isGlobalValid
  }
}];

